   "create_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
   "updater" varchar(255)DEFAULT '',
   "update_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
   "deleted" boolean NOT NULL DEFAULT FALSE,
   "tenant_id" bigint not null,
   PRIMARY KEY ("id")
);
COMMENT ON TABLE "system_oauth2_access_token" IS 'OAuth2 访问令牌';

CREATE TABLE IF NOT EXISTS "system_oauth2_refresh_token" (
    "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
    "user_id" bigint NOT NULL,
    "user_type" smallint NOT NULL,
    "refresh_token" varchar(255)NOT NULL,
    "client_id" varchar(255)NOT NULL,
    "scopes" varchar(255)NOT NULL,
    "approved" smallint NOT NULL DEFAULT 0,
    "expires_time" timestamp NOT NULL,
    "creator" varchar(255)DEFAULT '',
    "create_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updater" varchar(255)DEFAULT '',
    "update_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "deleted" boolean NOT NULL DEFAULT FALSE,
    "tenant_id" bigint not null DEFAULT 0,
    PRIMARY KEY ("id")
);
COMMENT ON TABLE "system_oauth2_refresh_token" IS 'OAuth2 刷新令牌';

CREATE TABLE IF NOT EXISTS "system_oauth2_code" (
     "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
     "user_id" bigint NOT NULL,
     "user_type" smallint NOT NULL,
     "code" varchar(255)NOT NULL,
     "client_id" varchar(255)NOT NULL,
     "scopes" varchar(255)NOT NULL,
     "expires_time" timestamp NOT NULL,
     "redirect_uri" varchar(255)NOT NULL,
     "state" varchar(255)NOT NULL,
     "creator" varchar(255)DEFAULT '',
     "create_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
     "updater" varchar(255)DEFAULT '',
     "update_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
     "deleted" boolean NOT NULL DEFAULT FALSE,
     PRIMARY KEY ("id")
);
COMMENT ON TABLE "system_oauth2_code" IS 'OAuth2 刷新令牌';

CREATE TABLE IF NOT EXISTS "system_mail_account" (
    "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
