-- ===== Manual supplement: member_config =====
CREATE SEQUENCE IF NOT EXISTS member_config_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1;

CREATE TABLE IF NOT EXISTS "member_config" (
    "id" bigint NOT NULL DEFAULT nextval('member_config_seq'),
    "point_trade_deduct_enable" boolean NOT NULL DEFAULT FALSE,
    "point_trade_deduct_unit_price" integer NOT NULL DEFAULT 0,
    "point_trade_deduct_max_price" integer NOT NULL DEFAULT 0,
    "point_trade_give_point" integer NOT NULL DEFAULT 0,
    "creator" varchar(64) DEFAULT '',
    "create_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updater" varchar(64) DEFAULT '',
    "update_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "deleted" boolean NOT NULL DEFAULT FALSE,
    "tenant_id" bigint NOT NULL DEFAULT 0,
    PRIMARY KEY ("id")
);
COMMENT ON TABLE "member_config" IS '会员配置';
COMMENT ON COLUMN "member_config"."point_trade_deduct_enable" IS '积分抵扣开关';
COMMENT ON COLUMN "member_config"."point_trade_deduct_unit_price" IS '积分抵扣，单位：分；1 积分抵扣多少分';
COMMENT ON COLUMN "member_config"."point_trade_deduct_max_price" IS '积分抵扣最大值';
COMMENT ON COLUMN "member_config"."point_trade_give_point" IS '1 元赠送多少分';

COMMIT;
